+const fn refresh_pid_hint(
+    current: &mut Option<u32>,
+    candidate: Option<u32>,
+    observed_at_ms: u64,
+    previous_last_seen: u64,
+) {
+    let Some(pid) = candidate else {
+        return;
+    };
+    if current.is_none() || observed_at_ms >= previous_last_seen {
+        *current = Some(pid);
+    }
+}
