+    candidate: Option<&str>,
+    observed_at_ms: u64,
+    previous_last_seen: u64,
+) {
+    let Some(version) = normalized(candidate) else {
+        return;
+    };
+    if current.is_none() || observed_at_ms >= previous_last_seen {
+        *current = Some(version);
