+
+impl ProjectLifecycleTracker {
+    #[must_use]
+    pub fn new(config: LifecycleTrackerConfig) -> Self {
+        Self {
+            config: config.normalized(),
+            resolver: ProjectAttributionResolver,
+            attributions: HashMap::new(),
+            lifecycles: HashMap::new(),
+            event_log: Vec::new(),
+        }
+    }
